import{_ as i,c as r,o as l,a5 as t,j as a}from"./chunks/framework.Dtwt352Q.js";const u=JSON.parse('{"title":"v1.1.46：修复 Think Blocks 显示问题","description":"","frontmatter":{},"headers":[],"relativePath":"changelog/v1.1.46.md","filePath":"changelog/v1.1.46.md","lastUpdated":1772014034000}'),n={name:"changelog/v1.1.46.md"};function s(o,e,h,d,c,p){return l(),r("div",null,[...e[0]||(e[0]=[t('<h1 id="v1-1-46-修复-think-blocks-显示问题" tabindex="-1">v1.1.46：修复 Think Blocks 显示问题 <a class="header-anchor" href="#v1-1-46-修复-think-blocks-显示问题" aria-label="Permalink to “v1.1.46：修复 Think Blocks 显示问题”">​</a></h1><p><strong>发布日期</strong>：2026年01月30日</p><hr><h2 id="一句话总结" tabindex="-1">一句话总结 <a class="header-anchor" href="#一句话总结" aria-label="Permalink to “一句话总结”">​</a></h2><p>这次更新修复了 Think Blocks（思考过程）无法正常显示的问题，让你能看到 AI 的完整思考过程。</p><hr><h2 id="问题修复-think-blocks-显示问题" tabindex="-1">问题修复：Think Blocks 显示问题 <a class="header-anchor" href="#问题修复-think-blocks-显示问题" aria-label="Permalink to “问题修复：Think Blocks 显示问题”">​</a></h2><h3 id="之前的问题" tabindex="-1">之前的问题 <a class="header-anchor" href="#之前的问题" aria-label="Permalink to “之前的问题”">​</a></h3><p>使用支持 Thinking 模式的模型（如 Claude 3.5 Sonnet）时，AI 的思考过程（Think Blocks）无法正常显示在对话中。这是因为 AI SDK 中间件阻止了 think blocks 作为助手消息内容返回。</p><h3 id="现在的情况" tabindex="-1">现在的情况 <a class="header-anchor" href="#现在的情况" aria-label="Permalink to “现在的情况”">​</a></h3><p>移除了导致问题的 AI SDK 中间件，Think Blocks 现在可以正常显示了。</p><h3 id="有什么好处" tabindex="-1">有什么好处？ <a class="header-anchor" href="#有什么好处" aria-label="Permalink to “有什么好处？”">​</a></h3><ul><li>可以看到 AI 的完整思考过程</li><li>更好地理解 AI 是如何得出结论的</li><li>对于调试和学习非常有帮助</li></ul><hr><h2 id="其他改进" tabindex="-1">其他改进 <a class="header-anchor" href="#其他改进" aria-label="Permalink to “其他改进”">​</a></h2><h3 id="tui-清理" tabindex="-1">TUI 清理 <a class="header-anchor" href="#tui-清理" aria-label="Permalink to “TUI 清理”">​</a></h3><p>移除了 TUI 中未使用的实验性配置项，让代码更加整洁。</p><h3 id="桌面端改进" tabindex="-1">桌面端改进 <a class="header-anchor" href="#桌面端改进" aria-label="Permalink to “桌面端改进”">​</a></h3><ul><li>添加了语言切换测试</li><li>改进了过渡动画、间距、滚动渐变效果和提示区域</li></ul><hr><h2 id="要不要升级" tabindex="-1">要不要升级？ <a class="header-anchor" href="#要不要升级" aria-label="Permalink to “要不要升级？”">​</a></h2><table tabindex="0"><thead><tr><th>情况</th><th>建议</th></tr></thead><tbody><tr><td>使用 Thinking 模式</td><td>✅ 强烈推荐（修复显示问题）</td></tr><tr><td>想看 AI 思考过程</td><td>✅ 推荐升级</td></tr><tr><td>用得好好的</td><td>可以等下次</td></tr></tbody></table><p><strong>升级命令</strong>：</p>',23),a("div",{class:"language-bash"},[a("button",{title:"Copy Code",class:"copy"}),a("span",{class:"lang"},"bash"),a("pre",null,[a("code",{"v-pre":""},"opencode upgrade")])],-1),t('<hr><h2 id="技术细节-可跳过" tabindex="-1">技术细节（可跳过） <a class="header-anchor" href="#技术细节-可跳过" aria-label="Permalink to “技术细节（可跳过）”">​</a></h2><details><summary>点击展开完整更新列表</summary><h3 id="core" tabindex="-1">Core <a class="header-anchor" href="#core" aria-label="Permalink to “Core”">​</a></h3><ul><li>Remove unused experimental keys from TUI (@IdrisGit)</li><li>Add continuous integration configuration</li><li>Remove AI SDK middleware that was preventing think blocks from being sent back as assistant message content</li></ul><h3 id="desktop" tabindex="-1">Desktop <a class="header-anchor" href="#desktop" aria-label="Permalink to “Desktop”">​</a></h3><ul><li>Change language test in app (@neriousy)</li><li>Add transitions, spacing improvements, scroll fade effects, and prompt area updates (@aaroniker)</li></ul><p><strong>Thank you to 3 community contributors:</strong></p><p>@aaroniker:</p><ul><li>feat: Transitions, spacing, scroll fade, prompt area update (#11168)</li></ul><p>@neriousy:</p><ul><li>test(app): change language test (#11295)</li></ul><p>@IdrisGit:</p><ul><li>chore(tui): remove unused experimental keys (#11195)</li></ul></details><hr><p><a href="./">← 返回更新日志</a></p>',5)])])}const b=i(n,[["render",s]]);export{u as __pageData,b as default};
